package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressIssue976Suite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // eval_collapse_vars
  // =========================================================================
  test("eval_collapse_vars".fail) {
    assertCompresses(
      input = """function f1() {
            var e = 7;
            var s = "abcdef";
            var i = 2;
            var eval = console.log.bind(console);
            var x = s.charAt(i++);
            var y = s.charAt(i++);
            var z = s.charAt(i++);
            eval(x, y, z, e);
        }
        function p1() { var a = foo(), b = bar(), eval = baz(); return a + b + eval; }
        function p2() { var a = foo(), b = bar(), eval = baz; return a + b + eval(); }
        (function f2(eval) {
            var a = 2;
            console.log(a - 5);
            eval("console.log(a);");
        })(eval)""".stripMargin.trim,
      expected = """function f1() {
            var e = 7,
                s = "abcdef",
                i = 2,
                eval = console.log.bind(console),
                x = s.charAt(i++),
                y = s.charAt(i++),
                z = s.charAt(i++);
            eval(x, y, z, e);
        }
        function p1() { return foo() + bar() + baz(); }
        function p2() { var a = foo(), b = bar(), eval = baz; return a + b + eval(); }
        (function f2(eval) {
            var a = 2;
            console.log(a - 5);
            eval("console.log(a);");
        })(eval)""".stripMargin.trim,
      options = AllOff.copy(
        booleans = true,
        collapseVars = true,
        comparisons = true,
        conditionals = true,
        deadCode = true,
        evaluate = true,
        hoistFuns = true,
        ifReturn = true,
        joinVars = true,
        keepFargs = true,
        loops = true,
        properties = true,
        sequencesLimit = 0,
        sideEffects = true,
        unused = true
      )
    )
  }

  // =========================================================================
  // eval_unused
  // =========================================================================
  test("eval_unused".fail) {
    assertCompresses(
      input = """function f1(a, eval, c, d, e) {
            return a('c') + eval;
        }
        function f2(a, b, c, d, e) {
            return a + eval('c');
        }
        function f3(a, eval, c, d, e) {
            return a + eval('c');
        }""".stripMargin.trim,
      expected = """function f1(a, eval) {
