        function f2(a, b, c, d, e) {
            return a + eval('c');
        }
        function f3(a, eval, c, d, e) {
            return a + eval('c');
        }""".stripMargin.trim,
      options = AllOff.copy(
        keepFargs = false,
        unused = true
